var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"크읏!","JPN":"くうっ！","ENG":"Urgh!","TWN":"唔！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"들어갔나......?!","JPN":"効いたでしょうか……！？","ENG":"Did it work?","TWN":"砍進去了嗎……？！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>불멸체 코어 원자제어부 기능 손상.</color>","JPN":"<color=#ffd34c>不滅体コアの原子制御部でシステム障害あり。</color>","ENG":"<color=#ffd34c>Immortal System Core's atom control system dysfunctional.</color>","TWN":"<color=#ffd34c>不滅者核心原子控制部機能損傷。</color>"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>손상부에 대한 긴급복구 불가...</color>","JPN":"<color=#ffd34c>障害部に対する緊急復旧不可……</color>","ENG":"<color=#ffd34c>Emergency repair... Inexecutable.</color>","TWN":"<color=#ffd34c>損傷部分無法緊急修復……</color>"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>기능 재활성화까지 원자 재조합 및 진화재생 시스템 셧다운.</color>","JPN":"<color=#ffd34c>障害部の復旧まで、原子の再組立および進化再生システムをシャットダウン。</color>","ENG":"<color=#ffd34c>Shutting down atom reconstitution and evolution/regeneration systems until recovery.</color>","TWN":"<color=#ffd34c>在機能恢復之前，關閉原子重組和進化再生系統。</color>"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"대단하군. 그 화망을 뚫고 내 몸에 박혀 있는 불멸체 코어에 기능고장을 일으키다니.","JPN":"すごいぞ、あの猛攻を突破して、私の体に埋め込まれている不滅体コアに障害を起こすなんて。","ENG":"Impressive. You broke through the barrage of fire and made the Immortal System Core inside me break down.","TWN":"真厲害呢。竟然能突破火力網，讓埋在我體內的不滅者核心發生故障。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 신세대의 잠재력이라고 생각해주시면 고맙겠네요.","JPN":"ハハ、これが新世代のポテンシャルだと思っていただければ。","ENG":"Hah hah, I'd appreciate it if you could think that the young generation has some potential.","TWN":"哈哈，如果你能把這看作是新世代的可能性，我會感到很光榮的。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"크윽!!","JPN":"くっ！！","ENG":"Hngh!","TWN":"嗚！！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"하지만 이젠 더 이상 필요가 없는 재생 시스템이 잠시 멈춘 것뿐이지.","JPN":"だが、これ以上必要のない再生システムが一時停止しただけだ。","ENG":"But what you did was merely stopping its regeneration system, which already went out of use.","TWN":"但你停止的也只是現在不再需要的再生系統而已。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"불멸체 코어의 에너지 투사능력은 건재하네.","JPN":"不滅体コアのエネルギー投射能力は今なお健在だ。","ENG":"The energy projection capabilities of the Immortal System Core is still as functional as ever.","TWN":"不滅者核心的能量投射能力仍舊完好無損！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"쿨럭......! 쿨럭......!","JPN":"ゲホッ……！　ゲホッ……！","ENG":"*Cough, cough!*","TWN":"咳咳……！咳咳……！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하...... 꽤 무리해서 넣은 일격이었는데...... 조금 얕았나 보네요. 아쉽게시리......","JPN":"ハハ……かなり無理くりの一撃だったのに……少し浅かったようですね、惜しいなぁ……","ENG":"Hah hah... That blow took quite an effort. I guess I had to go a little deeper. What a shame.","TWN":"哈哈……我用盡全力的一擊……好像還是太淺了呢，真是可惜……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"정말로 아까운 인재로군.","JPN":"実に捨てがたい人材だな。","ENG":"You're a great talent.","TWN":"你真的是很可惜的人才呢。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"아직도 나에게 적대한다는 생각에는 변함이 없나?","JPN":"まだ私に歯向かうつもりか？","ENG":"Do I really have to be an enemy to you?","TWN":"你還沒有想要改變和我作對的想法嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"자네가 보여준 힘과 지혜라면 신세계에서 새로운 인류를 이끄는 지도자가 되기에 부족함이 없어.","JPN":"君が見せてくれた力と知恵なら、新世界で新しい人類を導く指導者になるのに十分だ。","ENG":"The strength and wisdom you've shown me prove that you have the potential to be the leader of the new world.","TWN":"你們表現出來的力量和智慧，足以成為在新世界中帶領人類的領袖。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제안은 고맙지만 딱히 다니는 회사에 불만이 없어서요. 이직 생각은 없네요.","JPN":"提案はありがたいですが、今の所属会社にとくに不満はないので転職するつもりはありませんよ。","ENG":"Thanks for the offer, but I think I'll keep working for the company I'm in. I'm not looking for a career change just yet.","TWN":"很感謝你的提議，但我對現在的公司沒什麼不滿，沒想過要離職。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그리고 그 신세계의 지도자는 당신일 텐데요?","JPN":"それに、その新世界の指導者はあなたじゃありませんか？","ENG":"Anyway, isn't it you that's supposed to rule over the new world?","TWN":"而且新世界的領袖不是你的工作嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"꼭두각시 놀음은 취향에 없거든요.","JPN":"影武者は趣味じゃないんで。","ENG":"Being your puppet doesn't sound fun at all.","TWN":"我不喜歡人偶劇呢。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};